Steps:
[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP cleanup_pre]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_pre]
[GQL-OP get_def]
  query { productConfiguration(configurableProductId: "@td(CFG_HAT.id)" storeId: "{{STORE_ID}}") { configurationSections { id name type options { product { id name } } } } }
[GQL-EXEC get_def]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.0.id → VALID_SECTION_ID]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.0.options.0.product.id → VALID_OPTION_ID]
[GQL-OP add_item]
[GQL-VARS add_item] {"configurationSections": [{"sectionId": "{{VALID_SECTION_ID}}", "type": "Product", "option": {"productId": "{{VALID_OPTION_ID}}", "quantity": 1}}]}
  mutation AddItem($configurationSections: [ConfigurationSectionInput]) {
    addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "@td(CFG_HAT.id)" quantity: 1 configurationSections: $configurationSections }) {
      id itemsCount validationErrors { errorCode errorMessage objectId objectType }
      items { id productId quantity configurationItems { id sectionId productId } }
    }
  }
[GQL-EXEC add_item]
[GQL-CAPTURE add_item.data.addItem.items.0.id → LINE_ITEM_ID]
[GQL-CAPTURE add_item.data.addItem.items.0.configurationItems.0.id → ORIG_CONFIG_ITEM_ID]
[GQL-CAPTURE add_item.data.addItem.items.0.configurationItems.0.productId → ORIG_CONFIG_PRODUCT_ID]
[GQL-OP change_bad]
[GQL-VARS change_bad] {"configurationSections": [{"sectionId": "{{fabricated_section}}", "type": "Product", "option": {"productId": "{{VALID_OPTION_ID}}", "quantity": 1}}]}
  mutation ChangeBad($configurationSections: [ConfigurationSectionInput]) {
    changeCartConfiguredItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" lineItemId: "{{LINE_ITEM_ID}}" configurationSections: $configurationSections }) {
      id validationErrors { errorCode errorMessage objectId objectType }
      items { id productId quantity configurationItems { id sectionId productId } }
    }
  }
[GQL-EXEC change_bad]
[GQL-OP read_back]
  query { configurationItems(storeId: "{{STORE_ID}}" currencyCode: "USD" lineItemId: "{{LINE_ITEM_ID}}" userId: "{{USER_ID}}") { configurationItems { id sectionId productId } } }
[GQL-EXEC read_back]
[GQL-OP cleanup_post]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_post]

